import { useState } from 'react';
import { useRouter } from 'next/navigation';

interface MenuItemFormProps {
  restaurantId: string;
  initialData?: any;
}

export default function MenuItemForm({ restaurantId, initialData }: MenuItemFormProps) {
  const router = useRouter();
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setLoading(true);

    const formData = new FormData(e.currentTarget);
    const data = {
      name: formData.get('name'),
      description: formData.get('description'),
      price: parseFloat(formData.get('price') as string),
      category: formData.get('category'),
      restaurantId,
    };

    try {
      const response = await fetch('/api/menu', {
        method: initialData ? 'PUT' : 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(initialData ? { ...data, id: initialData.id } : data),
      });

      if (response.ok) {
        router.refresh();
        router.push(`/dashboard/restaurants/${restaurantId}`);
      }
    } catch (error) {
      console.error('Error saving menu item:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div>
        <label className="block text-sm font-medium">Name</label>
        <input
          name="name"
          defaultValue={initialData?.name}
          required
          className="w-full p-2 border rounded"
        />
      </div>
      <div>
        <label className="block text-sm font-medium">Description</label>
        <textarea
          name="description"
          defaultValue={initialData?.description}
          className="w-full p-2 border rounded"
        />
      </div>
      <div>
        <label className="block text-sm font-medium">Price</label>
        <input
          name="price"
          type="number"
          step="0.01"
          defaultValue={initialData?.price}
          required
          className="w-full p-2 border rounded"
        />
      </div>
      <div>
        <label className="block text-sm font-medium">Category</label>
        <input
          name="category"
          defaultValue={initialData?.category}
          className="w-full p-2 border rounded"
        />
      </div>
      <button
        type="submit"
        disabled={loading}
        className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600 disabled:bg-gray-400"
      >
        {loading ? 'Saving...' : initialData ? 'Update Item' : 'Add Item'}
      </button>
    </form>
  );
}
